// Helper to render product image (either URL or Emoji)
function getProductImageHTML(imageStr, name, extraStyle = '') {
  const fallback = 'https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&w=300&q=80';
  if (imageStr && (imageStr.startsWith('http://') || imageStr.startsWith('https://'))) {
    if (imageStr.includes('placeholder.com')) {
      return `<img src="${fallback}" alt="${name}" referrerpolicy="no-referrer" style="width: 100%; height: 100%; object-fit: cover; max-height: 100%; opacity: 0.55; ${extraStyle}">`;
    }
    return `<img src="${imageStr}" alt="${name}" referrerpolicy="no-referrer" onerror="this.onerror=null;this.src='${fallback}';this.style.opacity='0.55';" style="width: 100%; height: 100%; object-fit: contain; max-height: 100%; ${extraStyle}">`;
  }
  return `<img src="${fallback}" alt="${name}" referrerpolicy="no-referrer" style="width: 100%; height: 100%; object-fit: cover; max-height: 100%; opacity: 0.55; ${extraStyle}">`;
}

// 2. State Variable
let cart = [];

// 3. Load & Save Operations
function loadCart() {
  const savedCart = localStorage.getItem('baladi_cart');
  if (savedCart) {
    try {
      cart = JSON.parse(savedCart);
    } catch (e) {
      cart = [];
    }
  }
}

function saveCart() {
  localStorage.setItem('baladi_cart', JSON.stringify(cart));
  updateCartCounters();
}

// 4. Cart Operations
function addToCart(productId) {
  const product = PRODUCTS.find(p => p.id === productId);
  if (!product) return;

  const existingItem = cart.find(item => item.id === productId);
  if (existingItem) {
    existingItem.quantity += 1;
  } else {
    cart.push({
      id: product.id,
      name: product.name,
      price: product.price,
      unit: product.unit,
      category: product.category,
      image: product.image,
      quantity: 1
    });
  }

  saveCart();
  renderCart();
  showToast(`${product.name} added to cart!`);
}

function updateQuantity(productId, action) {
  const item = cart.find(item => item.id === productId);
  if (!item) return;

  if (action === 'increase') {
    item.quantity += 1;
  } else if (action === 'decrease') {
    item.quantity -= 1;
    if (item.quantity <= 0) {
      removeFromCart(productId);
      return;
    }
  }

  saveCart();
  renderCart();
}

function removeFromCart(productId) {
  const productIndex = cart.findIndex(item => item.id === productId);
  if (productIndex > -1) {
    const productName = cart[productIndex].name;
    cart.splice(productIndex, 1);
    saveCart();
    renderCart();
    showToast(`${productName} removed from cart.`);
  }
}

function clearCart() {
  cart = [];
  saveCart();
  renderCart();
}

function getCartTotal() {
  return cart.reduce((total, item) => total + (item.price * item.quantity), 0);
}

function getCartCount() {
  return cart.reduce((count, item) => count + item.quantity, 0);
}

// 5. User Interface Interactions & Rendering
function updateCartCounters() {
  const count = getCartCount();
  const badges = document.querySelectorAll('.cart-badge');
  badges.forEach(badge => {
    badge.textContent = count;
    badge.style.display = count > 0 ? 'flex' : 'none';
  });
}

function renderCart() {
  const cartContainer = document.querySelector('.cart-items-container');
  if (!cartContainer) return;

  if (cart.length === 0) {
    cartContainer.innerHTML = `
      <div class="cart-empty-message">
        <svg stroke="currentColor" fill="none" stroke-width="2" viewBox="0 0 24 24" height="1em" width="1em" xmlns="http://www.w3.org/2000/svg">
          <circle cx="9" cy="21" r="1"></circle>
          <circle cx="20" cy="21" r="1"></circle>
          <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"></path>
        </svg>
        <p>Your cart is empty.</p>
        <p style="font-size: 0.85rem;">Browse categories to add delicious products!</p>
      </div>
    `;
    
    const subtotalEl = document.querySelector('.subtotal-value');
    const vatEl = document.querySelector('.vat-value');
    const totalEl = document.querySelector('.total-value');
    const checkoutBtn = document.querySelector('.checkout-btn');

    if (subtotalEl) subtotalEl.textContent = 'AED 0.00';
    if (vatEl) vatEl.textContent = 'AED 0.00';
    if (totalEl) totalEl.textContent = 'AED 0.00';
    if (checkoutBtn) checkoutBtn.disabled = true;
    return;
  }

  cartContainer.innerHTML = cart.map(item => `
    <div class="cart-item">
      <div style="font-size: 2.8rem; background: var(--border); width: 60px; height: 60px; display: flex; align-items: center; justify-content: center; border-radius: var(--radius-sm); overflow: hidden;">
        ${getProductImageHTML(item.image, item.name, 'border-radius: var(--radius-sm);')}
      </div>
      <div class="cart-item-details">
        <div class="cart-item-title">${item.name}</div>
        <div class="cart-item-price">AED ${item.price.toFixed(2)} <span style="font-size: 0.75rem; color: var(--text-light);">/ ${item.unit}</span></div>
      </div>
      <div class="cart-item-actions">
        <button class="quantity-btn" onclick="updateQuantity('${item.id}', 'decrease')">-</button>
        <span class="cart-item-qty">${item.quantity}</span>
        <button class="quantity-btn" onclick="updateQuantity('${item.id}', 'increase')">+</button>
        <button class="remove-item-btn" onclick="removeFromCart('${item.id}')">
          <svg stroke="currentColor" fill="none" stroke-width="2" viewBox="0 0 24 24" height="1em" width="1em" xmlns="http://www.w3.org/2000/svg">
            <polyline points="3 6 5 6 21 6"></polyline>
            <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
            <line x1="10" y1="11" x2="10" y2="17"></line>
            <line x1="14" y1="11" x2="14" y2="17"></line>
          </svg>
        </button>
      </div>
    </div>
  `).join('');

  const subtotal = getCartTotal();
  const vat = subtotal * 0.05;
  const total = subtotal + vat;

  const subtotalEl = document.querySelector('.subtotal-value');
  const vatEl = document.querySelector('.vat-value');
  const totalEl = document.querySelector('.total-value');
  const checkoutBtn = document.querySelector('.checkout-btn');

  if (subtotalEl) subtotalEl.textContent = `AED ${subtotal.toFixed(2)}`;
  if (vatEl) vatEl.textContent = `AED ${vat.toFixed(2)}`;
  if (totalEl) totalEl.textContent = `AED ${total.toFixed(2)}`;
  if (checkoutBtn) checkoutBtn.disabled = false;

  // Render dedicated cart page if the renderer exists
  if (typeof window.renderCartPage === 'function') {
    window.renderCartPage();
  }
}

// Global pagination state
let currentPage = 1;
window.resetCurrentPage = () => { currentPage = 1; };
const itemsPerPage = 24;

// 6. Generate Products Grid for Page
function renderProductGrid(filterCategory = 'all', searchQuery = '', filterSubcategory = 'all') {
  const grid = document.querySelector('.products-grid');
  if (!grid) return;

  let filtered = PRODUCTS;

  // Apply category filtering
  if (filterCategory !== 'all') {
    filtered = PRODUCTS.filter(p => p.category === filterCategory);
  }

  // Apply subcategory filtering (supports nested child matches)
  if (filterSubcategory !== 'all') {
    filtered = filtered.filter(p => {
      if (!p.subcategory) return false;
      return p.subcategory === filterSubcategory || p.subcategory.startsWith(filterSubcategory + ' > ');
    });
  }

  // Apply search query filtering
  if (searchQuery.trim() !== '') {
    const q = searchQuery.toLowerCase().trim();
    filtered = filtered.filter(p => p.name.toLowerCase().includes(q) || p.category.replace('-', ' ').toLowerCase().includes(q));
  }

  // Set the product count badge if it exists
  const countBadge = document.getElementById('product-count') || document.querySelector('.product-count-badge');
  if (countBadge) {
    countBadge.textContent = `${filtered.length} Items`;
  }

  if (filtered.length === 0) {
    grid.innerHTML = `
      <div style="grid-column: 1 / -1; text-align: center; padding: 4rem 2rem; color: var(--text-light);">
        <p style="font-size: 1.5rem; font-weight: 700; margin-bottom: 0.5rem;">No products found</p>
        <p>Try searching for another product name or checking a different category.</p>
      </div>
    `;
    const pagContainer = document.getElementById('pagination-container');
    if (pagContainer) pagContainer.innerHTML = '';
    return;
  }

  // Apply pagination only if the pagination container exists in the DOM
  const pagContainer = document.getElementById('pagination-container');
  let paginatedItems = filtered;
  let totalPages = 1;

  if (pagContainer) {
    totalPages = Math.ceil(filtered.length / itemsPerPage);
    if (currentPage > totalPages) {
      currentPage = 1;
    }
    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = startIndex + itemsPerPage;
    paginatedItems = filtered.slice(startIndex, endIndex);
  }

  grid.innerHTML = paginatedItems.map(product => {
    // Deal vs regular price display logic
    const priceDisplay = product.isDeal 
      ? `<span style="text-decoration: line-through; color: var(--text-light); font-size: 0.9rem; margin-right: 0.5rem; font-weight: 400;">AED ${product.originalPrice.toFixed(2)}</span>AED ${product.price.toFixed(2)}`
      : `AED ${product.price.toFixed(2)}`;

    return `
      <div class="product-card" data-id="${product.id}">
        <span class="product-tag">${product.tag}</span>
        <div class="product-image-container" style="overflow: hidden;">
          <div style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; display: flex; align-items: center; justify-content: center; font-size: 6.5rem; user-select: none;">
            ${getProductImageHTML(product.image, product.name)}
          </div>
        </div>
        <div class="product-info">
          <span class="product-category">${(product.subcategory || product.category).replace(/^[^>]+>\s*/, '').replace(/-/g, ' ')}</span>
          <h3 class="product-title">${product.name}</h3>
          <div class="product-price-row">
            <div class="product-price">
              ${priceDisplay}
              <span style="font-size: 0.85rem; color: var(--text-light); font-weight: 500;">/ ${product.unit}</span>
            </div>
            <button class="add-to-cart-btn" onclick="addToCart('${product.id}')">
              <svg stroke="currentColor" fill="none" stroke-width="2.5" viewBox="0 0 24 24" height="1.2em" width="1.2em" xmlns="http://www.w3.org/2000/svg">
                <line x1="12" y1="5" x2="12" y2="19"></line>
                <line x1="5" y1="12" x2="19" y2="12"></line>
              </svg>
            </button>
          </div>
        </div>
      </div>
    `;
  }).join('');

  // Render pagination controls if pagination-container exists
  if (pagContainer) {
    if (totalPages <= 1) {
      pagContainer.innerHTML = '';
      return;
    }

    let paginationHTML = '';
    
    // Previous button
    if (currentPage > 1) {
      paginationHTML += `<button class="page-btn" onclick="changePage(${currentPage - 1}, '${filterCategory}', '${searchQuery}', '${filterSubcategory}')">&laquo; Prev</button>`;
    }

    // Numbered buttons (limit to showing at most 5 pages centered around current page)
    const maxButtons = 5;
    let startPage = Math.max(1, currentPage - Math.floor(maxButtons / 2));
    let endPage = Math.min(totalPages, startPage + maxButtons - 1);
    
    if (endPage - startPage + 1 < maxButtons) {
      startPage = Math.max(1, endPage - maxButtons + 1);
    }

    if (startPage > 1) {
      paginationHTML += `<button class="page-btn" onclick="changePage(1, '${filterCategory}', '${searchQuery}', '${filterSubcategory}')">1</button>`;
      if (startPage > 2) {
        paginationHTML += `<span style="align-self: center; padding: 0 0.25rem;">...</span>`;
      }
    }

    for (let p = startPage; p <= endPage; p++) {
      const activeClass = p === currentPage ? 'active' : '';
      paginationHTML += `<button class="page-btn ${activeClass}" onclick="changePage(${p}, '${filterCategory}', '${searchQuery}', '${filterSubcategory}')">${p}</button>`;
    }

    if (endPage < totalPages) {
      if (endPage < totalPages - 1) {
        paginationHTML += `<span style="align-self: center; padding: 0 0.25rem;">...</span>`;
      }
      paginationHTML += `<button class="page-btn" onclick="changePage(${totalPages}, '${filterCategory}', '${searchQuery}', '${filterSubcategory}')">${totalPages}</button>`;
    }

    // Next button
    if (currentPage < totalPages) {
      paginationHTML += `<button class="page-btn" onclick="changePage(${currentPage + 1}, '${filterCategory}', '${searchQuery}', '${filterSubcategory}')">Next &raquo;</button>`;
    }

    pagContainer.innerHTML = paginationHTML;
  }
}

// Global page change helper
window.changePage = (page, category, search, subcategory) => {
  currentPage = page;
  renderProductGrid(category, search, subcategory);
  // Scroll smoothly to popular products header
  const target = document.querySelector('.shop-categories-section') || document.querySelector('.products-grid');
  if (target) {
    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
};

// 6b. Live Deals Grid Renderer (5-Row Auto-Sliding Carousel with 3D Tilt Cards)
function renderDealsGrid() {
  const container = document.getElementById('live-deals-rows-container');
  if (!container) return;

  const deals = PRODUCTS.filter(p => p.isDeal || p.originalPrice);
  if (deals.length === 0) return;

  // Shuffle deals array to randomize items
  const shuffledDeals = [...deals];
  for (let i = shuffledDeals.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffledDeals[i], shuffledDeals[j]] = [shuffledDeals[j], shuffledDeals[i]];
  }

  // Distribute deals across 5 rows
  const rowsData = [[], [], [], [], []];
  shuffledDeals.forEach((deal, index) => {
    rowsData[index % 5].push(deal);
  });

  container.innerHTML = rowsData.map((rowData, rowIndex) => {
    // Triple the array for seamless infinite looping
    let baseItems = [...rowData];
    while (baseItems.length > 0 && baseItems.length < 8) {
      baseItems = baseItems.concat(rowData);
    }
    const rowItems = [...baseItems, ...baseItems, ...baseItems];
    
    const cardsHTML = rowItems.map(product => {
      // Determine badge label and color
      let badge = product.tag || '';
      let badgeColor = 'sale';
      
      if (badge.includes('%')) {
        badgeColor = 'sale';
      } else if (badge.toLowerCase().includes('new')) {
        badgeColor = 'new';
      } else if (badge.toLowerCase().includes('exclusive')) {
        badgeColor = 'exclusive';
      } else if (badge.toLowerCase().includes('limited')) {
        badgeColor = 'limited';
      } else {
        const colors = ['sale', 'new', 'exclusive', 'limited'];
        badgeColor = colors[Math.floor(product.price) % colors.length];
      }

      if (!badge) {
        // Creative food discount tags
        const discounts = ['17% OFF', '25% OFF', 'Fresh Deal', '15% OFF', 'Limited Pack', 'Special Price'];
        badge = discounts[Math.floor((product.price * 10) % discounts.length)];
        badgeColor = 'limited';
      }

      // Safe image rendering (falls back to placeholder emoji if needed)
      const isEmoji = !product.image || product.image.length < 8;
      const imageHTML = isEmoji 
        ? `<div style="display:flex;align-items:center;justify-content:center;font-size:5rem;width:100%;height:100%;background:#f3f4f6;">🍎</div>`
        : `<img src="${product.image}" alt="${product.name}" class="parallax-image" onerror="this.onerror=null; this.src='https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&w=400&q=80';">`;

      const desc = product.subcategory ? product.subcategory.split(' > ').pop() : 'Premium Selection';

      return `
        <div class="fashion-card-container" data-id="${product.id}">
          <div class="fashion-card animate-glow-pulse">
            <!-- Glass reflection layer -->
            <div class="fashion-card-glass"></div>
            
            <!-- Card content -->
            <div class="fashion-card-content">
              <!-- Parallax Image -->
              <div class="parallax-image-container">
                ${imageHTML}
              </div>
              
              <!-- Food Product Details -->
              <div class="p-5">
                <span style="color: var(--fashion-accent); font-weight: 800; font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.05em;">⚡ Flash Deal</span>
                <h3>${product.name}</h3>
                <p class="desc">${desc}</p>
                
                <div class="price-action-row">
                  <div class="price-display">
                    ${product.originalPrice ? `<span class="original-price">AED ${product.originalPrice.toFixed(2)}</span>` : ''}
                    <span class="current-price">AED ${product.price.toFixed(2)} <span style="font-size: 0.72rem; font-weight: 500; color: var(--text-light);">/ ${product.unit}</span></span>
                  </div>
                  <button class="shine-effect" onclick="addToCart('${product.id}')">
                    Shop now
                  </button>
                </div>
              </div>
            </div>
            
            <!-- Badge -->
            <div class="fashion-card-badge px-2.5 py-1 rounded-full text-xs font-medium capitalize animate-float badge-${badgeColor}">
              ${badge}
            </div>
          </div>
        </div>
      `;
    }).join('');

    return `
      <div class="flash-deals-row-wrapper" id="deals-row-wrapper-${rowIndex}">
        <div class="flash-deals-track" id="deals-track-${rowIndex}">
          ${cardsHTML}
        </div>
      </div>
    `;
  }).join('');

  initSliderEffects();
}

function initSliderEffects() {
  const wrappers = document.querySelectorAll('.flash-deals-row-wrapper');

  // Performance Optimization: Check if deals container is in viewport
  // to pause all animations when the deals section is off-screen.
  let containerInView = true;
  const container = document.getElementById('live-deals-rows-container');
  if (container && 'IntersectionObserver' in window) {
    const observer = new IntersectionObserver((entries) => {
      containerInView = entries[0].isIntersecting;
    }, { threshold: 0.01 });
    observer.observe(container);
  }

  wrappers.forEach((wrapper, rowIndex) => {
    const track = wrapper.querySelector('.flash-deals-track');
    if (!track) return;

    // Center the scroll position initially in the middle set of cloned items
    const initScroll = () => {
      const W = track.scrollWidth / 3;
      wrapper.scrollLeft = W;
    };
    
    // Run initialization
    setTimeout(initScroll, 100);
    window.addEventListener('load', initScroll);

    // Infinite loop scrolling logic
    wrapper.addEventListener('scroll', () => {
      const W = track.scrollWidth / 3;
      if (W <= 0) return;
      
      // If we scroll too close to the left edge, wrap around to the middle set
      if (wrapper.scrollLeft < 0.2 * W) {
        wrapper.scrollLeft += W;
      }
      // If we scroll too close to the right edge, wrap around to the middle set
      else if (wrapper.scrollLeft > 1.8 * W) {
        wrapper.scrollLeft -= W;
      }
    });

    // Mouse drag-to-scroll variables
    let isDown = false;
    let startX;
    let scrollLeft;
    let isDragging = false;

    wrapper.addEventListener('mousedown', (e) => {
      isDown = true;
      isDragging = true;
      startX = e.pageX - wrapper.offsetLeft;
      scrollLeft = wrapper.scrollLeft;
      wrapper.style.cursor = 'grabbing';
    });

    wrapper.addEventListener('mouseleave', () => {
      isDown = false;
      isDragging = false;
      wrapper.style.cursor = 'grab';
    });

    wrapper.addEventListener('mouseup', () => {
      isDown = false;
      wrapper.style.cursor = 'grab';
      // Short delay before resuming auto-scroll
      setTimeout(() => {
        isDragging = false;
      }, 200);
    });

    wrapper.addEventListener('mousemove', (e) => {
      if (!isDown) return;
      e.preventDefault();
      const x = e.pageX - wrapper.offsetLeft;
      const walk = (x - startX) * 2; // scroll speed multiplier
      wrapper.scrollLeft = scrollLeft - walk;
    });

    // Touch support (mobile swiping is natively handled by overflow-x: auto,
    // but we want to pause auto-scroll during touch)
    wrapper.addEventListener('touchstart', () => {
      isDragging = true;
    });

    wrapper.addEventListener('touchend', () => {
      setTimeout(() => {
        isDragging = false;
      }, 200);
    });

    // Performance Optimization: Cache hover state with mouseenter/mouseleave
    // instead of querying matches(':hover') inside requestAnimationFrame
    let isHovered = false;
    wrapper.addEventListener('mouseenter', () => {
      isHovered = true;
    });
    wrapper.addEventListener('mouseleave', () => {
      isHovered = false;
    });

    // Auto-scroll loop using requestAnimationFrame for butter-smooth animation
    // Alternating directions for premium parallax effect!
    const baseSpeed = 0.5; // pixels per frame
    const speed = (rowIndex % 2 === 0) ? baseSpeed : -baseSpeed;
    
    function step() {
      // Only scroll if container is in view, not hovered, and not active dragging
      if (containerInView && !isHovered && !isDragging) {
        wrapper.scrollLeft += speed;
      }
      requestAnimationFrame(step);
    }
    
    requestAnimationFrame(step);
  });

  // 3D Card mousemove listener for tilt and reflection effects
  const cards = document.querySelectorAll('.fashion-card');
  cards.forEach(card => {
    // Performance Optimization: Cache getBoundingClientRect on mouseenter
    // to prevent layout thrashing on every mousemove event.
    let rect = null;
    
    card.addEventListener('mouseenter', () => {
      rect = card.getBoundingClientRect();
    });

    card.addEventListener('mousemove', (e) => {
      if (!rect) {
        rect = card.getBoundingClientRect();
      }
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const centerX = rect.width / 2;
      const centerY = rect.height / 2;
      
      const rotationX = (y - centerY) / 12;
      const rotationY = -(x - centerX) / 12;

      card.style.transform = `rotateX(${rotationX}deg) rotateY(${rotationY}deg) scale(1.03)`;

      const glass = card.querySelector('.fashion-card-glass');
      if (glass) {
        const percentageX = (x / rect.width) * 100;
        const percentageY = (y / rect.height) * 100;
        glass.style.background = `radial-gradient(circle at ${percentageX}% ${percentageY}%, rgba(255, 255, 255, 0.25) 0%, rgba(255, 255, 255, 0.05) 75%)`;
      }
    });

    card.addEventListener('mouseleave', () => {
      rect = null;
      card.style.transform = 'rotateX(0deg) rotateY(0deg) scale(1)';
      const glass = card.querySelector('.fashion-card-glass');
      if (glass) {
        glass.style.background = 'rgba(255, 255, 255, 0.15)';
      }
    });
  });
}

// 6c. Subcategory Filter Pills Renderer (with two-level nested support for Fresh Food)
let activeParent = 'all';
let activeChild = 'all';

